from __future__ import annotations


def integrator_dashboard_html() -> str:
    return r'''<!doctype html>
<html lang="ru">
<head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Bitrix24 Engineering Audit — AI-BIT</title>
<style>
:root{color-scheme:light;--bg:#f5f6f8;--surface:#fff;--surface2:#fafbfc;--line:#e3e6ea;--text:#17191c;--muted:#6f747c;--accent:#5e6ad2;--critical:#b42318;--high:#c9364f;--medium:#a9670b;--low:#187653;--ok:#16835d;--mono:ui-monospace,SFMono-Regular,Consolas,"Liberation Mono",monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.45 Inter,ui-sans-serif,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}button,input,select{font:inherit}main{max-width:1700px;margin:auto;padding:24px 26px 80px}.header{display:flex;align-items:flex-start;justify-content:space-between;gap:20px;margin-bottom:16px}.eyebrow{font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--accent)}h1{font-size:25px;letter-spacing:-.03em;margin:4px 0}.muted{color:var(--muted)}.actions{display:flex;gap:8px;flex-wrap:wrap}.btn{border:1px solid var(--line);background:#fff;color:var(--text);border-radius:7px;padding:8px 11px;cursor:pointer}.btn:hover{background:#f7f7f8}.btn.primary{background:#202124;color:#fff;border-color:#202124}.metrics{display:grid;grid-template-columns:repeat(6,minmax(120px,1fr));gap:8px;margin-bottom:12px}.metric{background:var(--surface);border:1px solid var(--line);border-radius:9px;padding:12px}.metric span{display:block;color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.05em}.metric b{display:block;font-size:23px;margin-top:4px}.tabs{display:flex;gap:4px;overflow:auto;border-bottom:1px solid var(--line);margin-bottom:12px}.tab{border:0;background:transparent;color:#666b73;padding:9px 11px;cursor:pointer;border-bottom:2px solid transparent;white-space:nowrap}.tab.active{color:var(--text);border-bottom-color:var(--accent);font-weight:700}.view{display:none}.view.active{display:block}.panel{background:var(--surface);border:1px solid var(--line);border-radius:10px;overflow:hidden;margin-bottom:10px}.panel-head{display:flex;justify-content:space-between;align-items:center;gap:12px;padding:12px 14px;border-bottom:1px solid var(--line);background:var(--surface2)}.panel-head h2{font-size:14px;margin:0}.count{font:11px var(--mono);color:var(--muted)}table{width:100%;border-collapse:collapse}th,td{padding:9px 11px;text-align:left;border-bottom:1px solid #edf0f2;vertical-align:top}th{font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);background:#fbfcfd}tr:last-child td{border-bottom:0}.mono{font-family:var(--mono);font-size:11px;word-break:break-word}.badge{display:inline-flex;align-items:center;border-radius:999px;padding:3px 7px;font-size:10px;font-weight:800;text-transform:uppercase}.badge.critical,.badge.error,.badge.failed,.badge.missing{background:#fee4e2;color:var(--critical)}.badge.high{background:#ffeaed;color:var(--high)}.badge.medium,.badge.partial{background:#fff3dc;color:var(--medium)}.badge.low,.badge.ok,.badge.proposal_only,.badge.read_only{background:#e7f6ef;color:var(--ok)}.filters{display:flex;gap:7px;flex-wrap:wrap;margin-bottom:10px}.filters select,.filters input{border:1px solid var(--line);background:#fff;border-radius:7px;padding:7px 9px}.filters input{min-width:260px}.module-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.module-card{background:#fff;border:1px solid var(--line);border-radius:9px;padding:12px}.module-card h3{font-size:13px;margin:0 0 8px}.module-row{display:flex;justify-content:space-between;padding:3px 0;color:var(--muted)}details.issue,details.phase{background:#fff;border:1px solid var(--line);border-radius:9px;margin-bottom:7px;overflow:hidden}details[open]{border-color:#cfd3da}summary{list-style:none;cursor:pointer}summary::-webkit-details-marker{display:none}details.issue summary{display:grid;grid-template-columns:92px 180px minmax(260px,1fr) 150px;gap:10px;align-items:center;padding:10px 12px}.issue-body{border-top:1px solid var(--line);padding:12px;display:grid;grid-template-columns:1fr 1fr;gap:8px}.box{background:#fafbfc;border:1px solid #e9ecef;border-radius:7px;padding:10px}.box b{display:block;font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);margin-bottom:5px}.wide{grid-column:1/-1}.evidence{margin:0;padding-left:18px}.empty{padding:28px;text-align:center;color:var(--muted);background:#fff;border:1px solid var(--line);border-radius:9px}.source-list{display:grid;grid-template-columns:repeat(4,1fr);gap:7px}.source-item{display:flex;justify-content:space-between;align-items:center;background:#fff;border:1px solid var(--line);border-radius:8px;padding:9px 10px}.dot{width:8px;height:8px;border-radius:50%;background:#c7cbd1}.dot.ok{background:var(--ok)}.error-panel{display:none;padding:20px;border:1px solid #f1c5cb;background:#fff7f8;color:#8f2433;border-radius:10px;margin-bottom:12px}.error-panel.show{display:block}.policy{display:flex;gap:10px;align-items:flex-start;padding:12px 14px;background:#eef8f3;border:1px solid #cbe8da;border-radius:9px;margin-bottom:10px}.phase summary{display:flex;justify-content:space-between;gap:12px;align-items:center;padding:11px 13px}.phase-body{border-top:1px solid var(--line);padding:10px}.step{border:1px solid var(--line);border-radius:8px;margin-bottom:8px;overflow:hidden}.step-head{display:grid;grid-template-columns:50px 150px minmax(220px,1fr);gap:10px;padding:9px 11px;background:#fafbfc}.step-body{display:grid;grid-template-columns:1fr 1fr;gap:8px;padding:10px}.code{white-space:pre-wrap;margin:0;background:#111827;color:#e5e7eb;border-radius:7px;padding:10px;font:11px/1.5 var(--mono);overflow:auto}.warning{color:#8a5b09;background:#fff7e6;border:1px solid #f2d59a;border-radius:7px;padding:8px 10px}.blueprint-actions{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px}@media(max-width:1050px){.metrics{grid-template-columns:repeat(3,1fr)}.module-grid,.source-list{grid-template-columns:repeat(2,1fr)}details.issue summary{grid-template-columns:80px 140px 1fr}.issue-body,.step-body{grid-template-columns:1fr}}@media(max-width:650px){main{padding:16px 12px 70px}.header{display:block}.actions{margin-top:10px}.metrics{grid-template-columns:repeat(2,1fr)}.module-grid,.source-list{grid-template-columns:1fr}details.issue summary{grid-template-columns:75px 1fr}.summary-source{display:none}.filters input{min-width:100%;width:100%}.step-head{grid-template-columns:45px 1fr}}
</style>
</head>
<body><main>
<div class="header"><div><div class="eyebrow">Bitrix24 Engineering Audit</div><h1>Аудит интегратора</h1><div class="muted">Факт → объект → evidence → исправление → приёмка</div></div><div class="actions"><button class="btn" id="downloadAudit" type="button">Audit JSON</button><button class="btn" id="downloadBlueprint" type="button">Blueprint JSON</button><button class="btn" id="downloadSpec" type="button">ТЗ Markdown</button><button class="btn primary" id="refresh" type="button">Обновить</button></div></div>
<div id="error" class="error-panel"></div><div id="metrics" class="metrics"></div>
<nav class="tabs" id="tabs"><button class="tab active" data-view="overview">Обзор</button><button class="tab" data-view="findings">Замечания</button><button class="tab" data-view="rest">REST</button><button class="tab" data-view="reference">Эталонный diff</button><button class="tab" data-view="todo">Technical TODO</button><button class="tab" data-view="blueprint">Implementation Blueprint</button><button class="tab" data-view="sources">Источники</button></nav>
<section id="overview" class="view active"></section><section id="findings" class="view"></section><section id="rest" class="view"></section><section id="reference" class="view"></section><section id="todo" class="view"></section><section id="blueprint" class="view"></section><section id="sources" class="view"></section>
</main><script>
(()=>{'use strict';
const q=(s,r=document)=>r.querySelector(s);const qa=(s,r=document)=>Array.from(r.querySelectorAll(s));const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));let data=null,blueprint=null;
function badge(value){const v=String(value||'unknown').toLowerCase();return `<span class="badge ${esc(v)}">${esc(v)}</span>`}function metric(label,value){return `<div class="metric"><span>${esc(label)}</span><b>${esc(value??0)}</b></div>`}function panel(title,body,count=''){return `<div class="panel"><div class="panel-head"><h2>${esc(title)}</h2><span class="count">${esc(count)}</span></div>${body}</div>`}
function renderMetrics(){const s=data.summary||{},i=data.inventory||{};q('#metrics').innerHTML=[['Issues',s.total],['Critical',s.critical],['High',s.high],['REST failed',i.rest_failed],['Sources',`${i.available_sources||0}/${i.total_sources||0}`],['Blueprint',blueprint?.summary?.requirements||0]].map(x=>metric(x[0],x[1])).join('')}
function renderOverview(){const modules=data.module_summary||[];const cards=modules.length?`<div class="module-grid">${modules.map(x=>`<div class="module-card"><h3>${esc(x.module)}</h3><div class="module-row"><span>Всего</span><b>${x.total||0}</b></div><div class="module-row"><span>Critical / High</span><b>${(x.critical||0)+(x.high||0)}</b></div><div class="module-row"><span>Medium / Low</span><b>${(x.medium||0)+(x.low||0)}</b></div></div>`).join('')}</div>`:'<div class="empty">Подтверждённых замечаний нет.</div>';q('#overview').innerHTML=panel('Модули',cards,`${modules.length} modules`)+panel('Принцип аудита',`<div style="padding:13px 14px" class="mono">${esc(data.principle||'')}</div>`,data.version||'')}
function issueHtml(x){const evidence=(x.evidence||[]).length?`<ul class="evidence">${x.evidence.map(v=>`<li class="mono">${esc(v)}</li>`).join('')}</ul>`:'нет';return `<details class="issue" data-severity="${esc(x.severity)}" data-module="${esc(x.module)}"><summary>${badge(x.severity)}<span class="mono">${esc(x.module)}</span><b>${esc(x.title)}</b><span class="mono summary-source">${esc(x.source)}</span></summary><div class="issue-body"><div class="box"><b>Объект</b><span class="mono">${esc(x.object_ref||'не определён')}</span></div><div class="box"><b>Факт</b>${esc(x.finding)}</div><div class="box wide"><b>Evidence</b>${evidence}</div><div class="box"><b>Исправить</b>${esc(x.fix)}</div><div class="box"><b>Приёмка</b>${esc(x.verification)}</div>${Object.keys(x.technical||{}).length?`<div class="box wide"><b>Raw technical context</b><pre class="mono" style="white-space:pre-wrap;margin:0">${esc(JSON.stringify(x.technical,null,2))}</pre></div>`:''}</div></details>`}
function renderFindings(){const rows=data.issues||[];const modules=[...new Set(rows.map(x=>x.module))].sort();q('#findings').innerHTML=`<div class="filters"><select id="sevFilter"><option value="all">Severity: all</option><option>critical</option><option>high</option><option>medium</option><option>low</option></select><select id="moduleFilter"><option value="all">Module: all</option>${modules.map(x=>`<option>${esc(x)}</option>`).join('')}</select><input id="textFilter" placeholder="ID, метод, объект, текст ошибки"></div><div id="issueList">${rows.length?rows.map(issueHtml).join(''):'<div class="empty">Подтверждённых замечаний нет.</div>'}</div>`;['#sevFilter','#moduleFilter','#textFilter'].forEach(s=>q(s)?.addEventListener('input',filterIssues))}
function filterIssues(){const sev=q('#sevFilter')?.value||'all',mod=q('#moduleFilter')?.value||'all',text=(q('#textFilter')?.value||'').toLowerCase();qa('#issueList .issue').forEach(el=>{el.style.display=(sev==='all'||el.dataset.severity===sev)&&(mod==='all'||el.dataset.module===mod)&&(!text||el.textContent.toLowerCase().includes(text))?'block':'none'})}
function renderRest(){const rows=data.rest_checks||[];const body=rows.length?`<table><thead><tr><th>Status</th><th>Method</th><th>Capability</th><th>HTTP</th><th>Duration</th><th>Error</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${badge(x.status)}</td><td class="mono">${esc(x.method)}</td><td>${esc(x.capability)}</td><td class="mono">${esc(x.http_status??'')}</td><td class="mono">${esc(x.duration_ms??'')}</td><td class="mono">${esc(x.error||'')}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">REST probes отсутствуют.</div>';q('#rest').innerHTML=panel('REST probes',body,`${rows.length} checks`)}
function renderReference(){const rows=data.reference_diff||[];const body=rows.length?`<table><thead><tr><th>Status</th><th>Module</th><th>Capability</th><th>Object</th><th>Evidence</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${badge(x.status)}</td><td>${esc(x.module)}</td><td><b>${esc(x.capability)}</b></td><td class="mono">${esc(x.object_ref||'')}</td><td class="mono">${esc((x.evidence||[]).join(' | '))}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">Reference diff отсутствует.</div>';q('#reference').innerHTML=panel('Эталонный diff',body,`${rows.length} checks`)}
function renderTodo(){const rows=data.technical_todo||[];const body=rows.length?`<table><thead><tr><th>#</th><th>Priority</th><th>Module</th><th>Object</th><th>Task</th><th>Acceptance</th><th>Source</th></tr></thead><tbody>${rows.map(x=>`<tr><td class="mono">${x.priority}</td><td>${badge(x.severity)}</td><td>${esc(x.module)}</td><td class="mono">${esc(x.object_ref||'')}</td><td>${esc(x.task)}</td><td>${esc(x.acceptance)}</td><td class="mono">${esc(x.source)}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">Технических задач нет.</div>';q('#todo').innerHTML=panel('Technical TODO',body,`${rows.length} tasks`)}
function renderBlueprint(){if(!blueprint){q('#blueprint').innerHTML='<div class="empty">Blueprint недоступен.</div>';return}const policy=blueprint.execution_policy||{};const phases=blueprint.implementation_phases||[];const phaseHtml=phases.length?phases.map(p=>`<details class="phase" open><summary><b>Этап ${p.phase}. ${esc(p.name)}</b><span>${badge(p.severity)} · ${p.steps?.length||0} steps</span></summary><div class="phase-body">${(p.steps||[]).map(s=>`<div class="step"><div class="step-head"><span class="mono">#${s.order}</span><span>${esc(s.module)}</span><b>${esc(s.task)}</b></div><div class="step-body"><div class="box"><b>Объект</b><span class="mono">${esc(s.object_ref||'требует уточнения')}</span></div><div class="box"><b>Основание</b>${esc(s.basis)}</div><div class="box"><b>Приёмка</b>${esc(s.acceptance)}</div><div class="box"><b>REST proposal</b>${badge(s.rest?.mode)}<div class="mono" style="margin-top:5px">${esc(s.rest?.method||'manual')}</div></div><div class="box wide"><b>Параметры запроса</b><pre class="code">${esc(JSON.stringify(s.rest?.params||{},null,2))}</pre><div class="warning" style="margin-top:8px">${esc(s.rest?.note||'')}</div></div></div></div>`).join('')}</div></details>`).join(''):'<div class="empty">План внедрения пуст.</div>';q('#blueprint').innerHTML=`<div class="policy">${badge(blueprint.mode)}<div><b>Политика исполнения</b><div>${esc(policy.description||'')}</div></div></div>`+panel('Implementation phases',phaseHtml,`${phases.length} phases`)}
function renderSources(){const rows=Object.entries(data.sources||{});q('#sources').innerHTML=panel('Источники evidence',rows.length?`<div class="source-list" style="padding:10px">${rows.map(([k,v])=>`<div class="source-item"><span class="mono">${esc(k)}</span><span class="dot ${v?'ok':''}"></span></div>`).join('')}</div>`:'<div class="empty">Источники не обнаружены.</div>',`${rows.filter(x=>x[1]).length}/${rows.length}`)}
function render(){renderMetrics();renderOverview();renderFindings();renderRest();renderReference();renderTodo();renderBlueprint();renderSources()}
function downloadObject(obj,name,type='application/json'){const body=type==='application/json'?JSON.stringify(obj,null,2):obj;const blob=new Blob([body],{type});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name;a.click();URL.revokeObjectURL(url)}
async function load(){const btn=q('#refresh');btn.disabled=true;btn.textContent='Обновляю…';q('#error').classList.remove('show');try{const [auditResponse,blueprintResponse]=await Promise.all([fetch('/integrator-diagnostics/latest?_='+Date.now(),{cache:'no-store'}),fetch('/implementation-blueprint/latest?_='+Date.now(),{cache:'no-store'})]);if(!auditResponse.ok)throw new Error('Audit HTTP '+auditResponse.status);if(!blueprintResponse.ok)throw new Error('Blueprint HTTP '+blueprintResponse.status);data=await auditResponse.json();blueprint=await blueprintResponse.json();render()}catch(error){q('#error').textContent='Ошибка загрузки: '+error.message;q('#error').classList.add('show')}finally{btn.disabled=false;btn.textContent='Обновить'}}
q('#tabs').addEventListener('click',event=>{const button=event.target.closest('[data-view]');if(!button)return;qa('.tab').forEach(x=>x.classList.toggle('active',x===button));qa('.view').forEach(x=>x.classList.toggle('active',x.id===button.dataset.view))});q('#refresh').onclick=load;q('#downloadAudit').onclick=()=>data&&downloadObject(data,'bitrix24-engineering-audit.json');q('#downloadBlueprint').onclick=()=>blueprint&&downloadObject(blueprint,'implementation-blueprint.json');q('#downloadSpec').onclick=async()=>{const r=await fetch('/implementation-blueprint/spec.md?_='+Date.now(),{cache:'no-store'});if(r.ok)downloadObject(await r.text(),'bitrix24-technical-specification.md','text/markdown;charset=utf-8')};load();
})();
</script></body></html>'''
